-- JSONB + expression index
SELECT id FROM events
WHERE payload->>'userId' = '42';
CREATE INDEX ON events ((payload->>'userId'));

-- Window function: running total
SELECT id, amount, SUM(amount) OVER (ORDER BY id) AS running
FROM orders;

-- CTE
WITH ranked AS (SELECT *, ROW_NUMBER() OVER(PARTITION BY user_id ORDER BY ts DESC) rn FROM logs)
SELECT * FROM ranked WHERE rn=1;
